INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('4462f581-db3b-5244-86df-6c9a87ddcc9f', 'math-5eme', 'التناسب والنسبة المئوية', 'وضعيات التناسب وجداولها، معامل التناسب، إتمام جدول تناسب بالمعامل وبالخاصية الجمعية، حساب الرابع المتناسب، ومعنى النسبة المئوية البسيطة وحسابها من كمّية، مع مسائل من الحياة اليومية', '# ⚔️ التناسب والنسبة المئوية — بوّابة العلاقات الذكيّة

> 💡 «إذا عرفتَ ثمن واحدٍ، عرفتَ ثمن الجميع.»

أهلًا بك أيّها البطل في بوّابةٍ جديدة. في الفصل السابق تعلّمت **المحيط والمساحة**. اليوم نكتشف سلاحًا تستعمله كلّ يومٍ دون أن تشعر: حين تعرف ثمن قارورة ماءٍ واحدةٍ فتحسب ثمن ثلاث، أو حين يقول البائع «تخفيض 25%». هذه كلّها **تناسب** و**نسبة مئوية**.

## 🏰 ما هي وضعية التناسب؟

نقول إنّ كمّيتين في **وضعية تناسب** إذا كانت إحداهما تُساوي الأخرى **مضروبةً في العدد نفسه دائمًا**.

_مثال:_ ثمن قارورة الماء 2 دنانير. نملأ جدولًا:

| عدد القوارير | 1 | 2 | 3 | 5  |
| ------------ | - | - | - | -- |
| الثمن (د)    | 2 | 4 | 6 | 10 |

ننتقل من السطر الأوّل إلى الثاني **بالضرب في 2 في كلّ مرّة**: 1 × 2 = 2، و 3 × 2 = 6، و 5 × 2 = 10. لمّا يكون العدد المضروب فيه **ثابتًا**، الجدول جدول تناسب.

> 🗡️ علامة التناسب: «إذا تضاعف الأوّل تضاعف الثاني». قارورتان ثمنهما ضِعف ثمن قارورة.

## 🛡️ معامل التناسب

::: figure في جدول التناسب ننتقل من سطرٍ إلى آخر بضربٍ في معاملٍ ثابت، هنا اثنان
<svg viewBox="0 0 360 165"><text x="180.0" y="20.0" text-anchor="middle" font-size="11" font-weight="700" fill="#64748b" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">عدد القوارير ← الثمن بالدينار</text><rect x="6" y="34" width="34" height="34" rx="5" fill="#ede9fe" stroke="#7c3aed" stroke-width="1.6"/><rect x="6" y="74" width="34" height="34" rx="5" fill="#dbeafe" stroke="#1d4ed8" stroke-width="1.6"/><text x="23.0" y="56.0" text-anchor="middle" font-size="8" font-weight="700" fill="#6d28d9" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">قوارير</text><text x="23.0" y="96.0" text-anchor="middle" font-size="9" font-weight="700" fill="#1d4ed8" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">ثمن</text><rect x="40" y="34" width="54" height="34" rx="5" fill="#f5f3ff" stroke="#7c3aed" stroke-width="1.4"/><text x="67.0" y="57.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">1</text><rect x="40" y="74" width="54" height="34" rx="5" fill="#eff6ff" stroke="#1d4ed8" stroke-width="1.4"/><text x="67.0" y="97.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">2</text><path d="M67.0 70 V72" stroke="#16a34a" stroke-width="1"/><text x="89.0" y="72.0" text-anchor="middle" font-size="10" font-weight="700" fill="#15803d" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">× 2</text><rect x="102" y="34" width="54" height="34" rx="5" fill="#f5f3ff" stroke="#7c3aed" stroke-width="1.4"/><text x="129.0" y="57.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">2</text><rect x="102" y="74" width="54" height="34" rx="5" fill="#eff6ff" stroke="#1d4ed8" stroke-width="1.4"/><text x="129.0" y="97.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">4</text><path d="M129.0 70 V72" stroke="#16a34a" stroke-width="1"/><text x="151.0" y="72.0" text-anchor="middle" font-size="10" font-weight="700" fill="#15803d" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">× 2</text><rect x="164" y="34" width="54" height="34" rx="5" fill="#f5f3ff" stroke="#7c3aed" stroke-width="1.4"/><text x="191.0" y="57.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">3</text><rect x="164" y="74" width="54" height="34" rx="5" fill="#eff6ff" stroke="#1d4ed8" stroke-width="1.4"/><text x="191.0" y="97.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">6</text><path d="M191.0 70 V72" stroke="#16a34a" stroke-width="1"/><text x="213.0" y="72.0" text-anchor="middle" font-size="10" font-weight="700" fill="#15803d" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">× 2</text><rect x="226" y="34" width="54" height="34" rx="5" fill="#f5f3ff" stroke="#7c3aed" stroke-width="1.4"/><text x="253.0" y="57.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">5</text><rect x="226" y="74" width="54" height="34" rx="5" fill="#eff6ff" stroke="#1d4ed8" stroke-width="1.4"/><text x="253.0" y="97.0" text-anchor="middle" font-size="18" font-weight="700" fill="#1f2937" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">10</text><path d="M253.0 70 V72" stroke="#16a34a" stroke-width="1"/><text x="275.0" y="72.0" text-anchor="middle" font-size="10" font-weight="700" fill="#15803d" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">× 2</text><text x="180.0" y="138.0" text-anchor="middle" font-size="13" font-weight="700" fill="#15803d" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">معامل التناسب ثابت</text><text x="180.0" y="156.0" text-anchor="middle" font-size="13" font-weight="700" fill="#15803d" direction="ltr" unicode-bidi="isolate" paint-order="stroke" stroke="#ffffff" stroke-width="3.5" stroke-linejoin="round">4 ÷ 2 = 6 ÷ 3 = 10 ÷ 5 = 2</text></svg>
:::

العدد الثابت الذي **نضرب فيه** للانتقال من سطرٍ إلى آخر يُسمّى **معامل التناسب**.

$$معامل التناسب = الثمن ÷ العدد$$

في مثال القوارير: 4 ÷ 2 = 2، و 6 ÷ 3 = 2، و 10 ÷ 5 = 2. المعامل هو **2** دائمًا.

- للانتقال من السطر الأعلى إلى الأسفل: **نضرب** في المعامل.
- للرجوع من الأسفل إلى الأعلى: **نقسم** على المعامل.

> ⚠️ ليس كلّ جدولٍ جدولَ تناسب! انظر هذا الجدول: 3 ← 5 ثمّ 6 ← 8. هنا أضفنا 2 في الأسفل، لكنّ 5 ÷ 3 لا يساوي 8 ÷ 6. النسبة تغيّرت، فليست وضعية تناسب.

## 🔮 إتمام جدول تناسب

لإتمام خانةٍ ناقصة طريقتان:

**1) بالمعامل:** نجد المعامل أوّلًا، ثمّ نضرب أو نقسم به.

_مثال:_ 4 كرّاسات ثمنها 12 د. كم ثمن 7 كرّاسات؟ المعامل = 12 ÷ 4 = 3، إذن ثمن 7 = 7 × 3 = 21 د.

**2) بالخاصية الجمعية:** في جدول تناسبٍ، مجموع عمودين يوافق مجموعهما.

_مثال:_ إذا كان ثمن 2 = 6 وثمن 5 = 15، فثمن 7 = ثمن (2 + 5) = 6 + 15 = 21 د. (لأنّ 2 + 5 = 7).

## 🧮 الرابع المتناسب

أحيانًا نعرف **ثلاثة** أعداد في جدول تناسبٍ ونبحث عن **الرابع**. نسمّيه **الرابع المتناسب**.

| الكمّية أ | 3 | 12 |
| --------- | - | -- |
| الكمّية ب | 5 |  ؟ |

نجد المعامل من العمود الكامل: 5 ÷ 3 ليس عددًا بسيطًا، فننتقل بطريقةٍ أخرى: 12 = 3 × 4، إذن نضرب الأسفل أيضًا في 4: ؟ = 5 × 4 = 20.

_مثال محسوب:_ 5 كعكاتٍ تحتاج 200 غ سكّر. كم يلزم 8 كعكات؟
المعامل = 200 ÷ 5 = 40 (غ لكلّ كعكة)، إذن 8 × 40 = 320 غ. ✓

## 🔢 النسبة المئوية: معناها

**النسبة المئوية** تعني **«من بين 100»**. نكتبها برمز **%**.

$$25% = 25 من بين 100$$

- 100% = الكلّ كلّه.
- 50% = النصف (50 من بين 100).
- 25% = الرّبع (25 من بين 100).
- 10% = العُشر (10 من بين 100).

_مثال:_ إذا نجح 100% من التلاميذ فقد نجحوا جميعًا. وإذا نجح 50% فقد نجح نصفهم.

## ⚡ حساب نسبةٍ مئويةٍ من كمّية

لحساب نسبةٍ مئويةٍ من عددٍ نستعمل معانيها البسيطة:

| النسبة | معناها  | كيف نحسبها       |
| ------ | ------- | ---------------- |
| 50%    | النصف   | نقسم على 2       |
| 25%    | الرّبع  | نقسم على 4       |
| 10%    | العُشر  | نقسم على 10      |

_مثال محسوب:_ 25% من 80 = 80 ÷ 4 = 20. ✓
_مثال محسوب:_ 50% من 60 = 60 ÷ 2 = 30. ✓
_مثال محسوب:_ 10% من 90 = 90 ÷ 10 = 9. ✓

> 🗡️ حيلة سريعة: 10% تعني «احذف صفرًا» أو اقسم على 10. فـ 10% من 250 = 25.

## 📐 التعبير عن جزءٍ بنسبة مئوية

إذا كان الجزء **من بين 100** مباشرةً، فهو نسبة مئوية.

_مثال:_ في صفٍّ فيه 100 تلميذٍ، 30 منهم بنات. نسبة البنات = **30%**.
_مثال:_ نجح 40 تلميذًا من بين 100، فنسبة النجاح = **40%**.

> ⚠️ الخطأ الشائع: الخلط بين الجمع والتناسب. لإيجاد ثمن 6 إذا عرفت ثمن 3، **لا تجمع** ثمن 3 + 3 عشوائيًّا؛ بل اضرب في المعامل (أو لاحظ أنّ 6 = 3 × 2 فالثمن أيضًا × 2).

> 🏆 لقد عبرت بوّابة التناسب والنسبة المئوية! صرت تكمل جداول التناسب، وتجد الرابع المتناسب، وتحسب 25% و 50% و 10% من أيّ كمّية. استعدّ الآن للبوّابة الموالية: **الهندسة**.', '# 📜 ملخّص: التناسب والنسبة المئوية

- **وضعية التناسب:** كمّيتان في تناسبٍ إذا انتقلنا من إحداهما إلى الأخرى بالضرب في **العدد نفسه دائمًا** (مثل ثمن قواريرٍ ثمن الواحدة 2 د).
- **معامل التناسب:** العدد الثابت الذي نضرب فيه؛ نجده بقسمة سطرٍ على آخر (الثمن ÷ العدد)؛ نضرب به نزولًا ونقسم عليه صعودًا.
- **ليس كلّ جدولٍ متناسبًا:** إذا تغيّرت النسبة بين السطرين فالجدول ليس تناسبًا (الخاصية الجمعية لا الضربية).
- **إتمام جدول التناسب:** إمّا بالمعامل (نضرب/نقسم)، وإمّا بالخاصية الجمعية (مجموع عمودين يوافق مجموعهما).
- **الرابع المتناسب:** إذا عرفنا ثلاثة أعدادٍ في جدول تناسبٍ نوجد الرابع بالمعامل، مثل 5 كعكات → 200 غ، فـ 8 كعكات → 320 غ.
- **معنى النسبة المئوية:** % تعني «من بين 100»؛ 100% الكلّ، 50% النصف، 25% الرّبع، 10% العُشر.
- **حساب نسبةٍ من كمّية:** 50% = القسمة على 2، 25% = القسمة على 4، 10% = القسمة على 10؛ مثل 25% من 80 = 20.
- **التعبير عن جزءٍ بنسبة مئوية:** جزءٌ من بين 100 هو نسبة مئوية مباشرةً، مثل 30 من 100 = 30%.', 10, NULL)
