INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('9cee0386-651b-5a63-b23c-07ed1c8aa60d', 'math-5eme', 'الهندسة', 'المستقيمات المتوازية (∥) والمتعامدة (⊥) وإنشاؤها بالأدوات، والزوايا وأنواعها (قائمة، حادّة، منفرجة، مستقيمة) وقياسها بالمنقلة بالدرجات، والمثلّثات وأنواعها (قائم الزاوية، متساوي الساقين، متساوي الأضلاع، مختلف الأضلاع)، والرباعيّات (المربّع، المستطيل، المعيّن، متوازي الأضلاع) وخاصياتها، والدائرة والقرص (المركز، الشعاع، القطر = 2 × الشعاع) ورسمها بالبركار، والموسّط العمودي لقطعة', '# ⚔️ الهندسة — مملكة المستقيمات والأشكال

> 💡 «بالمسطرة والكوس والمنقلة والبركار تبني كلّ شكلٍ بدقّة: هذه أدواتُ مهندس الأبطال.»

أهلًا بك أيّها البطل! في رحلة **التناسب** تعلّمتَ أن تربط بين الأعداد. الآن ننتقل إلى **مملكة الهندسة**: نتعرّف على المستقيمات المتوازية والمتعامدة، ونقيس الزوايا بالمنقلة، ونصنّف المثلّثات والرباعيّات، ونرسم الدوائر بالبركار. أمسك أدواتك… المغامرة تبدأ.

## 📏 المستقيمان المتوازيان والمتعامدان

مستقيمان **متعامدان** إذا تقاطعا وكوّنا **زاوية قائمة** (90°). نكتب: (AB) ⊥ (CD). نتحقّق منهما ونرسمهما بـ**الكوس**، ونضع **مربّعًا صغيرًا** عند نقطة التقاطع علامةً على الزاوية القائمة.

<svg viewBox="0 0 100 100"><line x1="20" y1="20" x2="20" y2="84" stroke="currentColor" stroke-width="2.5"/><line x1="12" y1="58" x2="90" y2="58" stroke="currentColor" stroke-width="2.5"/><rect x="20" y="48" width="10" height="10" fill="none" stroke="#1f2937" stroke-width="1.5"/></svg>

مستقيمان **متوازيان** إذا لم يتقاطعا مهما امتدّا، ويبقى البعدُ بينهما **ثابتًا**. نكتب: (AB) ∥ (CD). نرسمهما بـ**المسطرة والكوس** (نُزلق الكوسَ على طول المسطرة)، ونضع **سهمين متماثلين** على المستقيمين علامةً على التوازي.

<svg viewBox="0 0 100 100"><line x1="8" y1="38" x2="92" y2="38" stroke="currentColor" stroke-width="2.5"/><line x1="8" y1="66" x2="92" y2="66" stroke="currentColor" stroke-width="2.5"/><polyline points="46,32 53,38 46,44" fill="none" stroke="#1f2937" stroke-width="1.6"/><polyline points="46,60 53,66 46,72" fill="none" stroke="#1f2937" stroke-width="1.6"/></svg>

> 🗡️ مثالٌ من الحياة: حافّتا المسطرة **متوازيتان**، وحافّتا الكتاب المتجاورتان **متعامدتان**.

> ⚠️ الفخّ الشائع: الظنّ أنّ كلّ مستقيمين متقاطعين متعامدان. التقاطعُ وحدَه لا يكفي — يجب أن تكون الزاويةُ **قائمة** (مربّعٌ صغير في الرسم).

## 📐 الزوايا وأنواعها

الزاويةُ فتحةٌ بين **نصفَي مستقيم** (ضلعين) لهما **رأسٌ مشترك**. نسمّيها بثلاثة أحرف، وحرفُ الرأس في الوسط: الزاوية ABC رأسُها B. كلّما اتّسعت الفتحةُ كبُر القيس (طولُ الضلعين لا يُغيّر شيئًا).

نصنّف الزوايا حسب القيس:

| النوع    | القيس                     |
| -------- | ------------------------- |
| حادّة    | أصغر من 90°               |
| قائمة    | يساوي 90°                 |
| منفرجة   | أكبر من 90° وأصغر من 180° |
| مستقيمة  | يساوي 180°                |

الزاويةُ **الحادّة** فتحتُها ضيّقة، والزاويةُ **القائمة** نعلّمها بمربّعٍ صغير، والزاويةُ **المنفرجة** فتحتُها واسعة:

<svg viewBox="0 0 200 80"><line x1="14" y1="64" x2="56" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="14" y1="64" x2="50" y2="36" stroke="currentColor" stroke-width="2.5"/><circle cx="14" cy="64" r="2.5" fill="currentColor"/><text x="22" y="78" font-size="11" fill="currentColor">حادّة</text><line x1="84" y1="64" x2="126" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="84" y1="64" x2="84" y2="22" stroke="currentColor" stroke-width="2.5"/><rect x="84" y="54" width="10" height="10" fill="none" stroke="#1f2937" stroke-width="1.5"/><circle cx="84" cy="64" r="2.5" fill="currentColor"/><text x="92" y="78" font-size="11" fill="currentColor">قائمة</text><line x1="154" y1="64" x2="196" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="154" y1="64" x2="124" y2="38" stroke="currentColor" stroke-width="2.5"/><circle cx="154" cy="64" r="2.5" fill="currentColor"/><text x="150" y="78" font-size="11" fill="currentColor">منفرجة</text></svg>

أمّا الزاويةُ **المستقيمة** فضلعاها على استقامةٍ واحدة وقيسُها 180°.

## 🧭 قياس الزاوية بالمنقلة

نقيس الزاويةَ بالدرجات (°) باستعمال **المنقلة**:

1. نضع **مركزَ المنقلة** على رأس الزاوية.
2. نُطابق **الخطّ الصفري** (0°) مع أحد الضلعين.
3. نقرأ العددَ الذي يمرّ عليه الضلعُ الآخر على التدريج.

في الشكل، الضلعُ الأوّل على 0° والضلعُ الآخر يمرّ على 60°، فقيسُ الزاوية **60°** (زاويةٌ حادّة):

<svg viewBox="0 0 120 80"><path d="M 18 66 A 42 42 0 0 1 102 66" fill="none" stroke="currentColor" stroke-width="2"/><line x1="18" y1="66" x2="102" y2="66" stroke="currentColor" stroke-width="1.2"/><line x1="60" y1="66" x2="102" y2="66" stroke="#1f2937" stroke-width="2.5"/><line x1="60" y1="66" x2="81" y2="29" stroke="#1f2937" stroke-width="2.5"/><circle cx="60" cy="66" r="2.5" fill="currentColor"/><path d="M 81 66 A 21 21 0 0 0 71 48" fill="none" stroke="#1f2937" stroke-width="1.4"/><text x="84" y="58" font-size="11" fill="currentColor">60°</text></svg>

ولرسم زاويةٍ بقيسٍ معطى (مثلًا 50°): نرسم ضلعًا، نضع المنقلةَ على طرفه، نُعلّم نقطةً عند 50°، ثمّ نصل الرأسَ بها.

> ⚠️ الفخّ الشائع: قراءةُ التدريج المقلوب على المنقلة. ابدأ دائمًا العدَّ من **الصفر** الموافق للضلع الأوّل، لا من 180°.

## 🔺 المثلّثات وأنواعها

المثلّثُ مضلّعٌ له **3 أضلاع** و**3 رؤوس** و**3 زوايا**. نصنّفه بطريقتين مختلفتين:

**حسب الأضلاع** (نعلّم الأضلاع المتساوية بـ**تشريطات** متماثلة):

- **متساوي الأضلاع:** أضلاعُه الثلاثة متساوية.
- **متساوي الساقين:** له ضلعان متساويان.
- **مختلف الأضلاع:** أضلاعُه الثلاثة مختلفة الأطوال.

<svg viewBox="0 0 200 84"><polygon points="34,72 14,72 24,28" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M 17 51 l 6 2" stroke="#1f2937" stroke-width="1.5"/><path d="M 31 51 l -6 2" stroke="#1f2937" stroke-width="1.5"/><path d="M 22 72 l 0 0" stroke="#1f2937" stroke-width="1.5"/><line x1="22" y1="70" x2="26" y2="70" stroke="#1f2937" stroke-width="1.5"/><text x="6" y="82" font-size="10" fill="currentColor">متساوي الأضلاع</text><polygon points="92,72 132,72 112,30" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M 99 53 l 5 -2" stroke="#1f2937" stroke-width="1.5"/><path d="M 124 53 l -5 -2" stroke="#1f2937" stroke-width="1.5"/><text x="86" y="82" font-size="10" fill="currentColor">متساوي الساقين</text><polygon points="158,72 196,72 174,34" fill="none" stroke="currentColor" stroke-width="2.5"/><text x="156" y="82" font-size="10" fill="currentColor">مختلف الأضلاع</text></svg>

**حسب الزوايا:**

- **قائمُ الزاوية:** فيه زاويةٌ قائمة (90°)، نعلّمها بمربّعٍ صغير.
- **حادُّ الزوايا:** كلُّ زواياه حادّة.
- **منفرجُ الزاوية:** فيه زاويةٌ منفرجة.

<svg viewBox="0 0 100 80"><polygon points="22,70 22,26 72,70" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="22" y="60" width="10" height="10" fill="none" stroke="#1f2937" stroke-width="1.5"/></svg>

> ⚠️ الفخّ الشائع: الخلطُ بين التصنيف حسب **الأضلاع** والتصنيف حسب **الزوايا**؛ هما تصنيفان مختلفان، فقد يكون المثلّثُ متساوي الساقين **و** قائمَ الزاوية في آنٍ واحد.

## 🔷 الرباعيّات وخاصياتها

الرباعيُّ مضلّعٌ له **4 أضلاع** و**4 رؤوس**. هذه عائلةٌ مهمّة، نميّز منها أربعة أنواع:

| الرباعيّ        | الأضلاع                         | الزوايا       |
| --------------- | ------------------------------- | ------------- |
| المربّع         | 4 أضلاع متساوية                 | 4 زوايا قائمة |
| المستطيل        | المتقابلة متساوية               | 4 زوايا قائمة |
| المعيّن         | 4 أضلاع متساوية                 | ليست قائمة    |
| متوازي الأضلاع   | المتقابلة متوازية ومتساوية      | ليست قائمة    |

في **متوازي الأضلاع** كلُّ ضلعين متقابلين **متوازيان ومتساويان**. والمربّعُ والمستطيلُ والمعيّنُ كلُّها حالاتٌ خاصّة من متوازي الأضلاع.

**المعيّن** متوازي أضلاعٍ أضلاعُه الأربعة متساوية (لكنّ زواياه ليست قائمة)، نعلّم تساوي أضلاعه بتشريطات:

<svg viewBox="0 0 100 90"><polygon points="50,16 86,46 50,76 14,46" fill="none" stroke="currentColor" stroke-width="2.5"/><path d="M 66 28 l 3 4" stroke="#1f2937" stroke-width="1.5"/><path d="M 66 64 l 3 -4" stroke="#1f2937" stroke-width="1.5"/><path d="M 34 28 l -3 4" stroke="#1f2937" stroke-width="1.5"/><path d="M 34 64 l -3 -4" stroke="#1f2937" stroke-width="1.5"/></svg>

**متوازي الأضلاع** أضلاعُه المتقابلة متوازية ومتساوية، نعلّم التوازي بأسهم متماثلة:

<svg viewBox="0 0 100 80"><polygon points="26,60 74,60 86,24 38,24" fill="none" stroke="currentColor" stroke-width="2.5"/><polyline points="47,57 52,60 47,63" fill="none" stroke="#1f2937" stroke-width="1.4"/><polyline points="59,21 64,24 59,27" fill="none" stroke="#1f2937" stroke-width="1.4"/></svg>

> 🗡️ تذكّر التداخل: **كلُّ مربّعٍ مستطيلٌ ومعيّن** في آنٍ واحد (أضلاعُه متساوية وزواياه قائمة)، وكلُّها متوازيات أضلاع.

## ⭕ الدائرة والقرص

**الدائرة** خطٌّ منحنٍ مغلق، كلُّ نقاطه على **بُعدٍ ثابت** من نقطةٍ تُسمّى **المركز** (O). نرسمها بـ**البركار**: نثبّت إبرتَه في المركز ونفتحه بطول الشعاع ثمّ ندير.

- **الشعاع** (نصف القطر): قطعةٌ تصل **المركزَ** بنقطةٍ على الدائرة، رمزُها r.
- **القطر**: قطعةٌ تصل نقطتين على الدائرة **مارّةً بالمركز**، رمزُها d.
- العلاقة: **القطرُ ضعفُ الشعاع**.

$$ d = 2 × r $$

<svg viewBox="0 0 100 100"><circle cx="50" cy="50" r="36" fill="none" stroke="currentColor" stroke-width="2.5"/><circle cx="50" cy="50" r="2.6" fill="currentColor"/><line x1="50" y1="50" x2="86" y2="50" stroke="#1f2937" stroke-width="2"/><line x1="14" y1="50" x2="50" y2="50" stroke="#1f2937" stroke-width="2"/><text x="64" y="46" font-size="11" fill="currentColor">r</text><text x="46" y="64" font-size="11" fill="currentColor">O</text><text x="22" y="46" font-size="11" fill="currentColor">d</text></svg>

**القرص** هو السطحُ الممتلئُ **داخل** الدائرة. فالدائرةُ هي الحدُّ (الخطّ)، والقرصُ هو المساحةُ بداخله.

> 🗡️ مثال: دائرةٌ شعاعُها 5 cm قطرُها d = 2 × 5 = 10 cm. وبالعكس، دائرةٌ قطرُها 8 cm شعاعُها 8 ÷ 2 = 4 cm.

## 📐 الموسّط العمودي لقطعة

**الموسّط العمودي** لقطعة [AB] هو المستقيمُ الذي يحقّق شرطين معًا:

- يمرّ بـ**منتصف** القطعة [AB] (نسمّيه M)،
- و**عمودي** عليها (يكوّن معها زاوية قائمة 90°).

نرسمه بالمسطرة والكوس: نحدّد المنتصفَ M، ثمّ نرسم العموديَّ على [AB] في M (مربّعٌ صغير علامةُ التعامد، وتشريطان متماثلان يدلّان على تساوي MA = MB):

<svg viewBox="0 0 120 90"><line x1="20" y1="60" x2="100" y2="60" stroke="currentColor" stroke-width="2.5"/><line x1="60" y1="14" x2="60" y2="84" stroke="#1f2937" stroke-width="2.5"/><rect x="60" y="50" width="10" height="10" fill="none" stroke="#1f2937" stroke-width="1.5"/><line x1="38" y1="56" x2="42" y2="64" stroke="#1f2937" stroke-width="1.5"/><line x1="78" y1="56" x2="82" y2="64" stroke="#1f2937" stroke-width="1.5"/><circle cx="20" cy="60" r="2.4" fill="currentColor"/><circle cx="100" cy="60" r="2.4" fill="currentColor"/><circle cx="60" cy="60" r="2.4" fill="currentColor"/><text x="14" y="74" font-size="11" fill="currentColor">A</text><text x="97" y="74" font-size="11" fill="currentColor">B</text><text x="62" y="74" font-size="11" fill="currentColor">M</text></svg>

> ⚠️ الفخّ الشائع: مستقيمٌ يمرّ بالمنتصف لكنّه **مائل** (غيرُ عمودي) ليس موسّطًا؛ والعموديُّ الذي **لا يمرّ بالمنتصف** ليس موسّطًا. لا بدّ من الشرطين معًا.

> 🏆 أحسنتَ أيّها البطل! صرتَ تميّز التوازيَ والتعامد، وتقيس الزوايا بالمنقلة، وتصنّف المثلّثات والرباعيّات، وترسم الدوائر والموسّطات. المغامرةُ التالية: **التناظر المحوري** — حيث تنعكس الأشكالُ كما في المرآة. 🏆', '# 📜 ملخّص: الهندسة

- **المتوازيان والمتعامدان:** متعامدان (⊥) يتقاطعان بزاوية قائمة 90° (مربّع صغير)؛ متوازيان (∥) لا يتقاطعان ويبقى البعد بينهما ثابتًا (سهمان متماثلان).
- **أنواع الزوايا:** حادّة < 90°، قائمة = 90°، منفرجة بين 90° و180°، مستقيمة = 180°؛ القيس يتعلّق بالفتحة لا بطول الضلعين.
- **قياس الزاوية بالمنقلة:** ضع المركز على الرأس، طابق الصفر مع ضلع، واقرأ العدد عند الضلع الآخر (وارسم زاوية بقيس معطى بنفس الطريقة).
- **أنواع المثلّثات:** حسب الأضلاع (متساوي الأضلاع، متساوي الساقين، مختلف الأضلاع)، وحسب الزوايا (قائم الزاوية، حادّ الزوايا، منفرج الزاوية) — تصنيفان مستقلّان.
- **الرباعيّات:** المربّع (4 أضلاع متساوية + 4 زوايا قائمة)، المستطيل (المتقابلة متساوية + زوايا قائمة)، المعيّن (4 أضلاع متساوية)، متوازي الأضلاع (المتقابلة متوازية ومتساوية).
- **الدائرة والقرص:** الدائرة خطّ منحنٍ كلّ نقاطه على بُعد ثابت من المركز؛ القطر = 2 × الشعاع (d = 2 × r)؛ ترسم بالبركار؛ القرص هو السطح بداخلها.
- **الموسّط العمودي لقطعة [AB]:** المستقيم العمودي على [AB] المارّ بمنتصفها M؛ يجب الشرطان معًا (عمودي + يمرّ بالمنتصف).', 11, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
