  ('009b278f-a8c8-5412-b640-68021ccf750d', 'fba283a6-d44f-5029-8bee-53d21f15c3eb', 'ما العلاقة الصحيحة بين العددين 0,7 و 0,68؟', '[{"id":"a","text":"0,7 < 0,68"},{"id":"b","text":"0,7 = 0,68"},{"id":"c","text":"0,7 > 0,68"},{"id":"d","text":"لا يمكن المقارنة"}]'::jsonb, 'c', 'الجزءان الصحيحان متساويان (0 = 0)؛ نُكمل 0,7 = 0,70 ونقارن الأعشار: 7 > 6، إذن 0,7 > 0,68. الخطأ الشائع هو الظنّ أنّ 0,68 أكبر لأنّ فيه أرقامًا أكثر بعد الفاصلة.', 1, 'mcq', NULL, NULL)
