INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('4e6bc528-5b2c-5d79-a1c6-ecdabb09b45f', 'fba283a6-d44f-5029-8bee-53d21f15c3eb', 'ما الترتيب التصاعديّ الصحيح للأعداد 4,5 و 4,05 و 4,5 المكتوب 4,50 و 4,55؟', '[{"id":"a","text":"4,05 < 4,5 = 4,50 < 4,55"},{"id":"b","text":"4,05 < 4,55 < 4,5 = 4,50"},{"id":"c","text":"4,5 = 4,50 < 4,05 < 4,55"},{"id":"d","text":"4,55 < 4,5 = 4,50 < 4,05"}]'::jsonb, 'a', 'العددان 4,5 و 4,50 متساويان (صفر غير مفيد). الأعشار: 0 في 4,05 فهو الأصغر، ثمّ 5 في 4,50 و 4,55، ونفصلهما بالجزء من مئة: 0 < 5 إذن 4,50 < 4,55. الترتيب: 4,05 < 4,5 = 4,50 < 4,55.', 2, 'mcq', NULL, NULL)
