INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('647cb46f-aaa9-52d3-af4f-5ee97c974a40', 'fba283a6-d44f-5029-8bee-53d21f15c3eb', 'أنا عددٌ عشري جزئي الصحيح 5، أكبر من 5,3 وأصغر من 5,4، ورقمُ الجزء من مئة عندي 7. من أكون؟', '[{"id":"a","text":"5,07"},{"id":"b","text":"5,37"},{"id":"c","text":"5,73"},{"id":"d","text":"5,47"}]'::jsonb, 'b', 'العدد بين 5,3 و 5,4 فأعشاره 3 وهو من النوع 5,3_، ورقمُ الجزء من مئة 7، فهو 5,37 لأنّ 5,30 < 5,37 < 5,40.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
