  ('2ace78e7-33e8-5b62-8fa0-aa5b776bf676', 'fba283a6-d44f-5029-8bee-53d21f15c3eb', 'كم عددًا عشريًّا له رقمٌ واحد بعد الفاصلة يقع تمامًا بين 2 و 3 (دون أن نَعُدّهما)؟', '[{"id":"a","text":"11"},{"id":"b","text":"10"},{"id":"c","text":"9"},{"id":"d","text":"8"}]'::jsonb, 'c', 'الأعداد ذات الرقم الواحد بعد الفاصلة بين 2 و 3 هي 2,1 و 2,2 حتّى 2,9، أي 9 أعداد. لا نَعُدّ 2 ولا 3.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
