  ('d36f7dc9-48d9-585a-981d-7deb6764cb8d', 'fba283a6-d44f-5029-8bee-53d21f15c3eb', 'رتّب تنازليًّا: 3,4 و 3,40 و 3,04 و 3,44.', '[{"id":"a","text":"3,4 = 3,40 > 3,44 > 3,04"},{"id":"b","text":"3,44 > 3,4 = 3,40 > 3,04"},{"id":"c","text":"3,44 > 3,04 > 3,4 = 3,40"},{"id":"d","text":"3,04 > 3,44 > 3,4 = 3,40"}]'::jsonb, 'b', 'العددان 3,4 و 3,40 متساويان. نقارن الأعشار: 4 في 3,44 و 3,40 و 3,4، و 0 في 3,04. ثمّ الجزء من مئة يفصل 3,44 (4) عن 3,40 (0). تنازليًّا: 3,44 > 3,4 = 3,40 > 3,04.', 5, 'mcq', NULL, NULL)
