INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c542e450-ea43-50ff-9827-75f3bcbc10ae', 'b45f98f1-ec63-55b4-9b45-b4f9adad5c20', 'نضع 30 كتابًا في صناديق، يَسَع كلّ صندوقٍ 4 كتب. كم صندوقًا نحتاج لوضع كلّ الكتب؟', '[{"id":"a","text":"7 صناديق"},{"id":"b","text":"8 صناديق"},{"id":"c","text":"6 صناديق"},{"id":"d","text":"9 صناديق"}]'::jsonb, 'b', '30 ÷ 4: الخارج 7 والباقي 2 (4 × 7 + 2 = 30). الكتابان المتبقّيان يحتاجان صندوقًا إضافيًّا، فالعدد 7 + 1 = 8 صناديق. الخطأ الشائع 7: ينسى الباقي ولا يكفي لكلّ الكتب.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
