  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a8cf5241-52dc-5c4e-bdb7-8f0c6f4a5923', 'b45f98f1-ec63-55b4-9b45-b4f9adad5c20', 'اشترى 6 أصدقاء هديّةً بثمن 45 دينارًا واقتسموا الثمن بالتساوي. كم يدفع كلّ واحد؟', '[{"id":"a","text":"7,5 دينارًا"},{"id":"b","text":"7 دنانير والباقي 3"},{"id":"c","text":"8 دنانير"},{"id":"d","text":"6,5 دينارًا"}]'::jsonb, 'a', 'في الأثمان نمدّد القسمة لخارجٍ عشريّ: 45 ÷ 6، الخارج 7 والباقي 3، نُنزل صفرًا (30) فـ 5، إذن 7,5. تحقّق: 6 × 7,5 = 45 ✓.', 3, 'mcq', NULL, NULL)
