  ('ba39e897-5f34-5a7a-a3d9-f0efdec1f1bb', 'b45f98f1-ec63-55b4-9b45-b4f9adad5c20', 'في قسمةٍ إقليدية المقسوم عليه 8 والخارج 12 والباقي 4. ما المقسوم؟', '[{"id":"a","text":"24"},{"id":"b","text":"96"},{"id":"c","text":"84"},{"id":"d","text":"100"}]'::jsonb, 'd', 'نستعمل العلاقة: المقسوم = المقسوم عليه × الخارج + الباقي = 8 × 12 + 4 = 96 + 4 = 100. والباقي 4 أصغر من 8 ✓.', 4, 'mcq', NULL, NULL)
