INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('73a9d6b6-76ea-5f86-85be-6e88818154ae', '5c0e6049-1972-5e48-8b43-94d43bef291b', 'أنا كسرٌ بسطي يساوي مقامي. ما قيمتي؟', '[{"id":"a","text":"أساوي 1"},{"id":"b","text":"أساوي 0"},{"id":"c","text":"أصغر من 1"},{"id":"d","text":"أكبر من 1"}]'::jsonb, 'a', 'حين يتساوى البسط والمقام نكون قد أخذنا كلّ الأجزاء، أي الوحدة كاملة، مثل 5/5 = 1. الخطأ الشائع الظنّ أنّه يساوي 0.', 1, 'mcq', NULL, NULL)
