INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7a6a2b57-ac03-526d-98e6-9a5e384f2ee1', '5c0e6049-1972-5e48-8b43-94d43bef291b', 'أيّ الكسرين أكبر: 1/2 أم 1/3؟', '[{"id":"a","text":"1/3"},{"id":"b","text":"1/2"},{"id":"c","text":"هما متساويان"},{"id":"d","text":"1/3 لأنّ مقامه أكبر"}]'::jsonb, 'b', 'كلّما كبر المقام صَغُر الجزء: تقسيم الوحدة إلى 3 يعطي أجزاءً أصغر من تقسيمها إلى 2، إذن 1/2 > 1/3. الخطأ الشائع ظنّ أنّ المقام الأكبر يعني كسرًا أكبر.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
