INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('87cc5605-3fc3-5304-ae2d-692064998797', '5c0e6049-1972-5e48-8b43-94d43bef291b', 'ربح وليدٌ 30 دينارًا، فأنفق 2/5 منها واحتفظ بالباقي. كم احتفظ؟', '[{"id":"a","text":"12 دينارًا"},{"id":"b","text":"6 دنانير"},{"id":"c","text":"18 دينارًا"},{"id":"d","text":"10 دنانير"}]'::jsonb, 'c', 'ما أنفقه 2/5 من 30 = (30 ÷ 5) × 2 = 6 × 2 = 12 دينارًا، فالباقي 30 − 12 = 18 دينارًا. الخطأ الشائع اختيار 12 (المبلغ المُنفق لا المحتفظ به).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
