  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('bf4e3807-cf69-5e4f-afca-cbaae317520e', '5c0e6049-1972-5e48-8b43-94d43bef291b', 'ما الكسر الذي يمثّله الجزء الملوّن، مكتوبًا في أبسط صورة؟ <svg viewBox="0 0 100 100"><rect x="6" y="36" width="88" height="28" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="6" y="36" width="33" height="28" fill="#d1d5db"/><line x1="17" y1="36" x2="17" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="28" y1="36" x2="28" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="39" y1="36" x2="39" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="50" y1="36" x2="50" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="61" y1="36" x2="61" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="72" y1="36" x2="72" y2="64" stroke="currentColor" stroke-width="2.5"/><line x1="83" y1="36" x2="83" y2="64" stroke="currentColor" stroke-width="2.5"/></svg>', '[{"id":"a","text":"3/5"},{"id":"b","text":"8/3"},{"id":"c","text":"1/3"},{"id":"d","text":"3/8"}]'::jsonb, 'd', 'قُسّم المستطيل إلى 8 أجزاء متساوية ولُوّن منها 3، فالكسر 3/8، ولا قاسم مشترك بين 3 و 8 غير 1، فهو أصلًا في أبسط صورة. الخطأ الشائع عدّ الأجزاء غير الملوّنة (5) فيُكتب 3/5.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
