  ('eab610c3-c595-59cb-b383-942fa3cc775d', '5c0e6049-1972-5e48-8b43-94d43bef291b', 'أيّ هذه الكسور لا يساوي 1/2؟', '[{"id":"a","text":"2/4"},{"id":"b","text":"3/5"},{"id":"c","text":"3/6"},{"id":"d","text":"5/10"}]'::jsonb, 'b', 'نختزل كلًّا منها: 2/4 = 1/2، و 3/6 = 1/2، و 5/10 = 1/2، أمّا 3/5 فلا قاسم مشترك بين 3 و 5، وهو أكبر من 1/2 (لأنّ 3/5 = 6/10 > 5/10). إذن 3/5 هو المختلف.', 5, 'mcq', NULL, NULL)
