INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('abadf395-0050-5bf4-bbf0-70135cdacc0c', '5c0e6049-1972-5e48-8b43-94d43bef291b', 'في قسمٍ فيه 24 تلميذًا، يحبّ 18 منهم مادّة الرياضيات. ما الكسر الممثّل لمحبّي الرياضيات في أبسط صورة؟', '[{"id":"a","text":"3/4"},{"id":"b","text":"6/8"},{"id":"c","text":"18/24"},{"id":"d","text":"2/3"}]'::jsonb, 'a', 'نختزل 18/24 بقسمة البسط والمقام على قاسمهما المشترك 6: 18 ÷ 6 = 3 و 24 ÷ 6 = 4، فنحصل على 3/4 وهي أبسط صورة. الخطأ الشائع التوقّف عند 6/8 (القسمة على 3 فقط) أو ترك الكسر 18/24 دون اختزال.', 6, 'mcq', NULL, NULL)
