INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6889eb26-71f0-5286-a0e3-c2192aca5e4a', '677e22b9-f5d2-5ae4-9803-9c8eb61c42f8', 'قارورةٌ سعتها 1,5 L مُلئت ثمّ شُرب منها 400 mL. كم بقي فيها بالميليلترات؟', '[{"id":"a","text":"1 100 mL"},{"id":"b","text":"1 900 mL"},{"id":"c","text":"350 mL"},{"id":"d","text":"1 460 mL"}]'::jsonb, 'a', 'نوحّد الوحدة: 1,5 L = 1 500 mL، ثمّ نطرح: 1 500 − 400 = 1 100. إذن البقيّة 1 100 mL. الخطأ الشائع 1 460 mL من تحويل 1,5 L إلى 1 500 mL ثمّ طرح 40 بدل 400.', 2, 'mcq', NULL, NULL)
