  ('456b7b1e-a937-52ad-94e4-5e64b57ef7b4', '3e2825ac-937a-59c4-b860-d69ac9ed6e9f', 'ما محيط مربّعٍ طول ضلعه 6 cm؟
<svg viewBox="0 0 70 80"><title>مربّعٌ طول ضلعه 6 cm</title><rect x="8" y="18" width="54" height="54" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="35" y="14" font-size="10" text-anchor="middle" fill="currentColor">6 cm</text></svg>', '[{"id":"a","text":"10 cm"},{"id":"b","text":"12 cm"},{"id":"c","text":"24 cm"},{"id":"d","text":"36 cm"}]'::jsonb, 'c', 'محيط المربّع = الضلع × 4 = 6 × 4 = 24 cm. كلّ أضلاع المربّع الأربعة متساوية فنضرب الضلع في 4.', 1, 'mcq', NULL, NULL)
