<svg viewBox="0 0 120 72"><title>مستطيلٌ طوله 7 cm وعرضه 4 cm</title><rect x="34" y="18" width="78" height="46" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="73" y="14" font-size="10" text-anchor="middle" fill="currentColor">7 cm</text><text x="28" y="44.5" font-size="10" text-anchor="end" fill="currentColor">4 cm</text></svg>', '[{"id":"a","text":"11 cm"},{"id":"b","text":"22 cm"},{"id":"c","text":"28 cm"},{"id":"d","text":"28 cm²"}]'::jsonb, 'b', 'محيط المستطيل = (الطول + العرض) × 2 = (7 + 4) × 2 = 11 × 2 = 22 cm. لا نتوقّف عند 11 بل نضرب المجموع في 2 لأنّ للمستطيل أربعة أضلاع.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
