  ('afe915ad-3fe5-5eb7-969a-3c1e68142017', '4972d18f-a808-5101-941b-23f9433c29a0', 'ما محيط هذا المربّع؟ <svg viewBox="0 0 100 100"><rect x="26" y="22" width="52" height="52" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="42" y="17" font-size="10" fill="currentColor">8 cm</text></svg>', '[{"id":"a","text":"32 cm"},{"id":"b","text":"24 cm"},{"id":"c","text":"16 cm"},{"id":"d","text":"64 cm"}]'::jsonb, 'a', 'ضلع المربّع في الرسم 8 cm، فالمحيط = الضلع × 4 = 8 × 4 = 32 cm. الناتج 64 خطأٌ لأنّه 8 × 8 وهو حساب المساحة لا المحيط.', 6, 'mcq', NULL, NULL)
