INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a44e86be-9974-5cbe-848e-1079d58ed516', 'f1a57f55-07de-500f-8140-3c4df12ef87b', 'مربّعٌ طول ضلعه 6 m. ما الفرق بين محيطه ومساحته (عددًا)؟', '[{"id":"a","text":"المحيط 24 m والمساحة 36 m²"},{"id":"b","text":"المحيط 36 m والمساحة 24 m²"},{"id":"c","text":"المحيط 24 m² والمساحة 36 m"},{"id":"d","text":"المحيط 12 m والمساحة 36 m²"}]'::jsonb, 'a', 'المحيط = الضلع × 4 = 6 × 4 = 24 m، والمساحة = الضلع × الضلع = 6 × 6 = 36 m². الخطأ الشائع: قلب العمليّتين أو الخلط بين الوحدتين؛ المحيط وحدته m والمساحة وحدتها m².', 2, 'mcq', NULL, NULL)
