INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('81ff07fe-fb01-506b-a0f2-360efb232574', 'f1a57f55-07de-500f-8140-3c4df12ef87b', 'ما مساحة هذا المستطيل؟ <svg viewBox="0 0 100 100"><rect x="12" y="32" width="76" height="42" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="38" y="27" font-size="10" fill="currentColor">9 cm</text><text x="2" y="56" font-size="10" fill="currentColor">4 cm</text></svg>', '[{"id":"a","text":"13 cm²"},{"id":"b","text":"26 cm²"},{"id":"c","text":"36 cm"},{"id":"d","text":"36 cm²"}]'::jsonb, 'd', 'من الرسم الطول 9 cm والعرض 4 cm، فالمساحة = الطول × العرض = 9 × 4 = 36 cm². الخطأ الشائع: حساب المحيط (9 + 4) × 2 = 26 cm بدل المساحة المطلوبة، أو نسيان أنّ وحدة المساحة مربّعة (cm² لا cm).', 3, 'mcq', NULL, NULL)
