INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2055461a-70d5-513d-a0c2-23a978bdf774', 'f1a57f55-07de-500f-8140-3c4df12ef87b', 'أرضيّة غرفةٍ مربّعةٍ طول ضلعها 5 m. نريد تبليطها كاملةً. ما المساحة التي نغطّيها؟', '[{"id":"a","text":"10 m²"},{"id":"b","text":"20 m²"},{"id":"c","text":"25 m²"},{"id":"d","text":"25 m"}]'::jsonb, 'c', 'البلاط يغطّي السطح فنحسب المساحة = الضلع × الضلع = 5 × 5 = 25 m². الخطأ الشائع: حساب المحيط 5 × 4 = 20 m، لكنّ المحيط للسياج لا للبلاط، والبلاط مساحةٌ بوحدة m².', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
