INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('23981e69-21a9-506f-9ab6-8185394deb17', 'f1a57f55-07de-500f-8140-3c4df12ef87b', 'ما مساحة هذا الشكل المركّب على شكل حرف L؟ <svg viewBox="0 0 110 100"><polygon points="15,15 60,15 60,50 95,50 95,85 15,85" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><line x1="15" y1="50" x2="60" y2="50" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/><text x="32" y="11" font-size="8" fill="currentColor">5 cm</text><text x="2" y="35" font-size="8" fill="currentColor">4 cm</text><text x="44" y="71" font-size="8" fill="currentColor">8 cm</text><text x="2" y="71" font-size="8" fill="currentColor">3 cm</text></svg>', '[{"id":"a","text":"24 cm²"},{"id":"b","text":"44 cm²"},{"id":"c","text":"20 cm²"},{"id":"d","text":"40 cm²"}]'::jsonb, 'b', 'نقسّم الشكل بالخطّ المتقطّع إلى مستطيلين: علويٌّ 5 × 4 = 20 cm²، وسفليٌّ 8 × 3 = 24 cm². المساحة = 20 + 24 = 44 cm². الخطأ الشائع: حساب مستطيلٍ واحدٍ فقط (20 أو 24) ونسيان جمع الجزأين.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
