  ('4ffb6c9f-049f-5292-a1f1-8cbe8a735c9b', 'f1a57f55-07de-500f-8140-3c4df12ef87b', 'مستطيلٌ مساحته 48 cm² وطوله 8 cm. ما عرضه؟
<svg viewBox="0 0 100 76"><title>مستطيلٌ مساحته 48 cm² وطوله 8 cm</title><rect x="8" y="18" width="84" height="50" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="50" y="14" font-size="10" text-anchor="middle" fill="currentColor">8 cm</text><text x="50" y="46.5" font-size="10" text-anchor="middle" fill="currentColor">S = 48 cm²</text></svg>', '[{"id":"a","text":"6 cm"},{"id":"b","text":"40 cm"},{"id":"c","text":"16 cm"},{"id":"d","text":"384 cm"}]'::jsonb, 'a', 'بما أنّ المساحة = الطول × العرض، فالعرض = المساحة ÷ الطول = 48 ÷ 8 = 6 cm. تحقّق: 8 × 6 = 48 cm² ✓. الخطأ الشائع: طرح الطول من المساحة (48 − 8 = 40) بدل القسمة عليه.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
