  ('75a87df3-7adb-5d51-b35a-1a7fae3d1337', 'ef192471-4797-59da-b075-abf262b47963', 'ما مساحة هذا المستطيل؟ <svg viewBox="0 0 100 100"><rect x="14" y="34" width="72" height="38" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="38" y="29" font-size="10" fill="currentColor">11 cm</text><text x="2" y="56" font-size="10" fill="currentColor">3 cm</text></svg>', '[{"id":"a","text":"14 cm²"},{"id":"b","text":"28 cm²"},{"id":"c","text":"33 cm²"},{"id":"d","text":"33 cm"}]'::jsonb, 'c', 'من الرسم الطول 11 cm والعرض 3 cm، فالمساحة = 11 × 3 = 33 cm². الناتج 28 خطأٌ لأنّه المحيط (11 + 3) × 2، والسؤال عن المساحة.', 4, 'mcq', NULL, NULL)
