INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('b93f490b-9a54-5f87-a8a5-cd3b9488f9f1', 'ef192471-4797-59da-b075-abf262b47963', 'مربّعٌ محيطه 32 cm. ما طول ضلعه؟', '[{"id":"a","text":"8 cm"},{"id":"b","text":"16 cm"},{"id":"c","text":"28 cm"},{"id":"d","text":"128 cm"}]'::jsonb, 'a', 'في المربّع: الضلع = المحيط ÷ 4 = 32 ÷ 4 = 8 cm. تحقّق: 8 × 4 = 32 cm ✓. الناتج 128 خطأٌ لأنّه ضربٌ في 4 بدل القسمة عليه.', 5, 'mcq', NULL, NULL)
