INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('fbc53652-200a-58e3-b43c-f9831b6b1621', 'ef192471-4797-59da-b075-abf262b47963', 'بلاطةٌ مربّعةٌ طول ضلعها 30 cm، ومستطيلٌ طوله 60 cm وعرضه 20 cm. أيّهما مساحته أكبر؟', '[{"id":"a","text":"البلاطة المربّعة (900 cm²)"},{"id":"b","text":"المستطيل (1 200 cm²)"},{"id":"c","text":"متساويان في المساحة"},{"id":"d","text":"لا يمكن المقارنة"}]'::jsonb, 'b', 'مساحة المربّع = 30 × 30 = 900 cm²، ومساحة المستطيل = 60 × 20 = 1 200 cm². بما أنّ 1 200 أكبر من 900، فمساحة المستطيل أكبر.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
