INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a59ca625-72c8-54ef-97da-0d5d05b7c56f', 'de876987-1446-5507-900e-1949b8169c32', 'مستطيلٌ مساحته 54 m² وعرضه 6 m. ما محيطه؟
<svg viewBox="0 0 134 76"><title>مستطيلٌ مساحته 54 m² وعرضه 6 m</title><rect x="34" y="18" width="92" height="50" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><text x="28" y="46.5" font-size="10" text-anchor="end" fill="currentColor">6 m</text><text x="80" y="46.5" font-size="10" text-anchor="middle" fill="currentColor">S = 54 m²</text></svg>', '[{"id":"a","text":"15 m"},{"id":"b","text":"30 m"},{"id":"c","text":"60 m"},{"id":"d","text":"9 m"}]'::jsonb, 'b', 'أوّلًا الطول = المساحة ÷ العرض = 54 ÷ 6 = 9 m. ثمّ المحيط = (الطول + العرض) × 2 = (9 + 6) × 2 = 15 × 2 = 30 m. تحقّق: 9 × 6 = 54 m² ✓. الخطأ الشائع: التوقّف عند الطول 9 m وعدّه جوابًا للمحيط.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c752b9a0-9b97-5029-b5d6-18bea409ee66', 'de876987-1446-5507-900e-1949b8169c32', 'أرضٌ مربّعةٌ مساحتها 49 m². كم مترًا من السياج نحتاج لإحاطتها؟', '[{"id":"a","text":"7 m"},{"id":"b","text":"14 m"},{"id":"c","text":"28 m"},{"id":"d","text":"196 m"}]'::jsonb, 'c', 'نجد الضلع أوّلًا: المساحة = الضلع × الضلع = 49، والعدد الذي ضربُه في نفسه 49 هو 7، فالضلع 7 m. السياج محيطٌ = 7 × 4 = 28 m. الخطأ الشائع: عدّ المساحة 49 جوابًا للسياج، لكنّ السياج محيطٌ بوحدة m لا m².', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a1ed2fdf-a154-5f8a-9eb7-8ba92fdb20e4', 'de876987-1446-5507-900e-1949b8169c32', 'ما مساحة هذا الشكل المركّب؟ <svg viewBox="0 0 120 100"><polygon points="15,15 105,15 105,45 55,45 55,85 15,85" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><line x1="55" y1="45" x2="55" y2="15" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/><text x="72" y="11" font-size="8" fill="currentColor">9 cm</text><text x="107" y="33" font-size="8" fill="currentColor">3 cm</text><text x="28" y="11" font-size="8" fill="currentColor">4 cm</text><text x="2" y="53" font-size="8" fill="currentColor">7 cm</text></svg>', '[{"id":"a","text":"27 cm²"},{"id":"b","text":"28 cm²"},{"id":"c","text":"63 cm²"},{"id":"d","text":"55 cm²"}]'::jsonb, 'd', 'نقسّم الشكل بالخطّ المتقطّع إلى مستطيلين: يمينٌ علويٌّ طوله 9 وعرضه 3 ⟵ 9 × 3 = 27 cm²، ويسارٌ طوله 4 وارتفاعه 7 ⟵ 4 × 7 = 28 cm². المساحة = 27 + 28 = 55 cm². الخطأ الشائع: حساب مستطيلٍ واحدٍ فقط (27 أو 28) ونسيان الجمع.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('7b824c08-7e44-5db5-8d4e-ba144ce44fae', 'de876987-1446-5507-900e-1949b8169c32', 'غرفةٌ مستطيلةٌ طولها 6 m وعرضها 4 m. نبلّطها ببلاطاتٍ مربّعةٍ ضلع كلٍّ منها 1 m. كم بلاطةً نحتاج؟', '[{"id":"a","text":"10 بلاطة"},{"id":"b","text":"20 بلاطة"},{"id":"c","text":"24 بلاطة"},{"id":"d","text":"24 m"}]'::jsonb, 'c', 'عدد البلاطات = مساحة الغرفة ÷ مساحة البلاطة. مساحة الغرفة = 6 × 4 = 24 m²، ومساحة كلّ بلاطة = 1 × 1 = 1 m²، فالعدد = 24 ÷ 1 = 24 بلاطة. الخطأ الشائع: حساب المحيط (6 + 4) × 2 = 20 بدل المساحة.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('371acd69-9011-5eab-a3ad-bfd6d1c4f017', 'de876987-1446-5507-900e-1949b8169c32', 'مستطيلٌ ومربّعٌ لهما نفس المحيط. ضلع المربّع 8 cm، وعرض المستطيل 5 cm. ما مساحة المستطيل؟', '[{"id":"a","text":"40 cm²"},{"id":"b","text":"55 cm²"},{"id":"c","text":"64 cm²"},{"id":"d","text":"32 cm²"}]'::jsonb, 'b', 'محيط المربّع = 8 × 4 = 32 cm، وهو نفسه محيط المستطيل. نصف المحيط = 32 ÷ 2 = 16 = الطول + العرض، فالطول = 16 − 5 = 11 cm. مساحة المستطيل = 11 × 5 = 55 cm². الخطأ الشائع: طرح العرض من المحيط كاملًا (32 − 5) دون أخذ نصف المحيط أوّلًا.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('63c59a2a-f8b1-5846-941d-7c5283b77d8e', 'de876987-1446-5507-900e-1949b8169c32', 'بستانٌ مستطيلٌ طوله 30 m وعرضه 20 m، في وسطه حوضٌ مربّعٌ ضلعه 10 m لا يُزرع. ما المساحة المزروعة؟
<svg viewBox="0 0 138 90"><title>بستانٌ مستطيلٌ 30 m × 20 m وفي وسطه حوضٌ مربّعٌ ضلعه 10 m (المنطقة الرماديّة مزروعة)</title><rect x="34" y="18" width="96" height="64" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><rect x="66" y="34" width="32" height="32" fill="#ffffff" stroke="currentColor" stroke-width="2.5"/><text x="82" y="14" font-size="10" text-anchor="middle" fill="currentColor">30 m</text><text x="28" y="53.5" font-size="10" text-anchor="end" fill="currentColor">20 m</text><text x="82" y="31" font-size="9" text-anchor="middle" fill="currentColor">10 m</text><text x="82" y="53.5" font-size="9" text-anchor="middle" fill="#1f2937">حوض</text></svg>', '[{"id":"a","text":"500 m²"},{"id":"b","text":"100 m²"},{"id":"c","text":"600 m²"},{"id":"d","text":"700 m²"}]'::jsonb, 'a', 'المساحة المزروعة = مساحة البستان − مساحة الحوض. مساحة البستان = 30 × 20 = 600 m²، ومساحة الحوض = 10 × 10 = 100 m²، فالمزروع = 600 − 100 = 500 m². الخطأ الشائع: نسيان طرح الحوض وعدّ 600 m² كلّها مزروعة.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

