  ('cb9dced1-95f8-505b-982b-37b71320d400', '235b4fe8-bcaf-5ce3-80d9-e683bbfb770d', 'ما محيط مربّعٍ طول ضلعه 12 cm؟', '[{"id":"a","text":"24 cm"},{"id":"b","text":"48 cm"},{"id":"c","text":"144 cm"},{"id":"d","text":"48 cm²"}]'::jsonb, 'b', 'محيط المربّع = الضلع × 4 = 12 × 4 = 48 cm. الخطأ الشائع: حساب 12 × 12 = 144 وهو المساحة لا المحيط؛ والمحيط وحدته cm.', 1, 'mcq', NULL, NULL)
