INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('3923c81d-7394-560e-b63c-053c54720c73', '235b4fe8-bcaf-5ce3-80d9-e683bbfb770d', 'ما مساحة هذا الشكل المركّب على شكل حرف L؟ <svg viewBox="0 0 110 100"><polygon points="15,15 55,15 55,55 95,55 95,85 15,85" fill="#e5e7eb" stroke="currentColor" stroke-width="2.5"/><line x1="55" y1="55" x2="15" y2="55" stroke="currentColor" stroke-width="1.5" stroke-dasharray="4 3"/><text x="30" y="11" font-size="8" fill="currentColor">4 cm</text><text x="2" y="38" font-size="8" fill="currentColor">4 cm</text><text x="50" y="75" font-size="8" fill="currentColor">8 cm</text><text x="2" y="75" font-size="8" fill="currentColor">3 cm</text></svg>', '[{"id":"a","text":"16 cm²"},{"id":"b","text":"24 cm²"},{"id":"c","text":"40 cm²"},{"id":"d","text":"32 cm²"}]'::jsonb, 'c', 'نقسّم بالخطّ المتقطّع إلى مستطيلين: علويٌّ 4 × 4 = 16 cm²، وسفليٌّ 8 × 3 = 24 cm². المساحة = 16 + 24 = 40 cm². الخطأ الشائع: حساب جزءٍ واحدٍ فقط ونسيان جمع المستطيلين.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('960a30a7-11b3-5c21-988f-7242a4b9dc09', '235b4fe8-bcaf-5ce3-80d9-e683bbfb770d', 'قاعةٌ مستطيلةٌ طولها 8 m وعرضها 5 m. نريد وضع شريطٍ زخرفيٍّ حول حافّتها وفرشَ سجّادٍ يغطّي أرضها. ما طول الشريط وما مساحة السجّاد؟', '[{"id":"a","text":"الشريط 26 m والسجّاد 40 m²"},{"id":"b","text":"الشريط 40 m والسجّاد 26 m²"},{"id":"c","text":"الشريط 13 m والسجّاد 40 m²"},{"id":"d","text":"الشريط 26 m² والسجّاد 40 m"}]'::jsonb, 'a', 'الشريط يحيط بالحافّة فهو محيطٌ = (8 + 5) × 2 = 26 m. والسجّاد يغطّي السطح فهو مساحةٌ = 8 × 5 = 40 m². الخطأ الشائع: قلب المقدارين (محيط للسجّاد ومساحة للشريط) أو الخلط بين وحدتي m وm².', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

