  ('58a35102-a121-5479-99cb-9a0a8468024e', '167d6edc-6121-5fb2-be09-e3b475279006', 'متى نقول إنّ جدولًا هو جدول تناسب؟', '[{"id":"a","text":"إذا أضفنا العدد نفسه في كلّ مرّة"},{"id":"b","text":"إذا ضربنا في العدد نفسه دائمًا للانتقال بين السطرين"},{"id":"c","text":"إذا كانت كلّ الأعداد زوجيّة"},{"id":"d","text":"إذا كان السطر الثاني أكبر من الأوّل"}]'::jsonb, 'b', 'في جدول التناسب ننتقل من سطرٍ إلى آخر بالضرب في العدد نفسه دائمًا، وهو معامل التناسب. الإضافة ليست تناسبًا.', 1, 'mcq', NULL, NULL)
