INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('a47eff83-7ed2-52a7-a1d1-7645c625c0e9', '4c8d7fc9-b70e-51c7-b74f-6c7e951d6aab', 'أيُّ جدولٍ ممّا يلي **ليس** جدول تناسب؟', '[{"id":"a","text":"1 يوافق 5، و 2 يوافق 10، و 3 يوافق 15"},{"id":"b","text":"2 يوافق 6، و 4 يوافق 12، و 5 يوافق 15"},{"id":"c","text":"1 يوافق 4، و 3 يوافق 12، و 5 يوافق 20"},{"id":"d","text":"3 يوافق 5، و 6 يوافق 8، و 9 يوافق 11"}]'::jsonb, 'd', 'في الجداول a و b و c نضرب في عددٍ ثابت (5، ثمّ 3، ثمّ 4). أمّا في d فقد أضفنا 3 في الأعلى و 3 في الأسفل: 5 ÷ 3 لا يساوي 8 ÷ 6، فالنسبة تغيّرت وليس تناسبًا (إضافةٌ لا ضرب).', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
