INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('e925b1d6-fed0-5e4f-abe7-11c2530210bb', '4c8d7fc9-b70e-51c7-b74f-6c7e951d6aab', 'في جدول تناسبٍ: 2 يوافق 6، و 5 يوافق 15. باستعمال الخاصية الجمعية، كم يوافق 7؟', '[{"id":"a","text":"18"},{"id":"b","text":"20"},{"id":"c","text":"21"},{"id":"d","text":"9"}]'::jsonb, 'c', 'بما أنّ 7 = 2 + 5، فإنّ ما يوافق 7 = (ما يوافق 2) + (ما يوافق 5) = 6 + 15 = 21. ونتحقّق بالمعامل: 6 ÷ 2 = 3، و 7 × 3 = 21. ✓ الخطأ الشائع هو جمع 7 + 2 أو نسيان أنّ 7 = 2 + 5.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
