INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('31b8b584-aa7b-5cb4-a266-b041141f64b0', '6761c369-c470-560b-986a-3ba55c15d263', 'في جدول تناسبٍ: 4 يوافق 10، و 6 يوافق 15. باستعمال الخاصية الجمعية، كم يوافق 10؟', '[{"id":"a","text":"20"},{"id":"b","text":"30"},{"id":"c","text":"25"},{"id":"d","text":"19"}]'::jsonb, 'c', 'بما أنّ 10 = 4 + 6، فإنّ ما يوافق 10 = (ما يوافق 4) + (ما يوافق 6) = 10 + 15 = 25. ونتحقّق بالمعامل: 10 ÷ 4 = 2,5، و 10 × 2,5 = 25. ✓ الخطأ الشائع هو جمع 10 + 6 بدل ملاحظة أنّ 10 = 4 + 6.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
