  ('1e3c29f7-9c29-5834-ba27-d3798fa4b1db', '6761c369-c470-560b-986a-3ba55c15d263', 'أيُّ جدولٍ ممّا يلي **ليس** جدول تناسب؟', '[{"id":"a","text":"2 يوافق 10، و 3 يوافق 15، و 4 يوافق 20"},{"id":"b","text":"1 يوافق 6، و 2 يوافق 12، و 4 يوافق 24"},{"id":"c","text":"4 يوافق 7، و 8 يوافق 11، و 12 يوافق 15"},{"id":"d","text":"3 يوافق 9، و 5 يوافق 15، و 7 يوافق 21"}]'::jsonb, 'c', 'في a و b و d المعامل ثابت (5، ثمّ 6، ثمّ 3). أمّا في c فقد أضفنا 4 في الأعلى و 4 في الأسفل: 7 ÷ 4 لا يساوي 11 ÷ 8، فالنسبة تتغيّر. الخطأ الشائع هو الظنّ أنّ زيادةً ثابتةً في السطرين تكفي للتناسب، والصحيح أنّ التناسب ضربٌ في معاملٍ ثابت.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
