  ('01ae2eae-803d-5c7a-b496-210d0d58c7c4', '9ef183bf-ef81-5713-a53a-bdc5b961f985', 'في الشكل، الضلعُ الأوّل على 0° والضلعُ الآخر يمرّ على التدريج. كم قيسُ الزاوية وما نوعُها؟ <svg viewBox="0 0 120 80"><path d="M 18 66 A 42 42 0 0 1 102 66" fill="none" stroke="currentColor" stroke-width="2"/><line x1="18" y1="66" x2="102" y2="66" stroke="currentColor" stroke-width="1.2"/><line x1="60" y1="66" x2="102" y2="66" stroke="#1f2937" stroke-width="2.5"/><line x1="60" y1="66" x2="42" y2="28" stroke="#1f2937" stroke-width="2.5"/><circle cx="60" cy="66" r="2.5" fill="currentColor"/><text x="30" y="40" font-size="11" fill="currentColor">120°</text></svg>', '[{"id":"a","text":"120° منفرجة"},{"id":"b","text":"60° حادّة"},{"id":"c","text":"120° حادّة"},{"id":"d","text":"90° قائمة"}]'::jsonb, 'a', 'الضلعُ الآخر يمرّ على 120° مائلًا نحو اليسار، والقيسُ بين 90° و180° فالزاوية منفرجة. الخطأ الشائع: قراءةُ 60° بالعدّ من 180° (التدريج المقلوب) بدل العدّ من الصفر.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('6924286b-d4fb-5a06-b98f-6b480f926143', '9ef183bf-ef81-5713-a53a-bdc5b961f985', 'أيُّ مستقيمٍ هو الموسّط العمودي للقطعة [AB]؟ <svg viewBox="0 0 120 90"><line x1="20" y1="60" x2="100" y2="60" stroke="currentColor" stroke-width="2.5"/><line x1="60" y1="14" x2="60" y2="84" stroke="#1f2937" stroke-width="2.5"/><rect x="60" y="50" width="10" height="10" fill="none" stroke="#1f2937" stroke-width="1.5"/><line x1="38" y1="56" x2="42" y2="64" stroke="#1f2937" stroke-width="1.5"/><line x1="78" y1="56" x2="82" y2="64" stroke="#1f2937" stroke-width="1.5"/><circle cx="20" cy="60" r="2.4" fill="currentColor"/><circle cx="100" cy="60" r="2.4" fill="currentColor"/><text x="14" y="74" font-size="11" fill="currentColor">A</text><text x="97" y="74" font-size="11" fill="currentColor">B</text></svg>', '[{"id":"a","text":"المستقيمُ العمودي على [AB] المارُّ بمنتصفها"},{"id":"b","text":"أيُّ مستقيمٍ يمرّ بالمنتصف ولو كان مائلًا"},{"id":"c","text":"أيُّ مستقيمٍ عمودي على [AB] ولو بعيدًا عن المنتصف"},{"id":"d","text":"المستقيمُ الموازي للقطعة [AB]"}]'::jsonb, 'a', 'الموسّطُ العمودي يحقّق الشرطين معًا: عمودي على [AB] (المربّع الصغير) ويمرّ بمنتصفها (التشريطان: المنتصف على بُعدٍ متساوٍ من A وB). الخطأ الشائع: الاكتفاءُ بشرطٍ واحد (المرور بالمنتصف وحدَه أو التعامد وحدَه).', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('796dd212-00ed-5901-ac48-fe57aa6c640d', '9ef183bf-ef81-5713-a53a-bdc5b961f985', 'المستقيمان (د1) و(د2) كلاهما عمودي على المستقيم نفسِه (د). ماذا نستنتج عن (د1) و(د2)؟', '[{"id":"a","text":"متعامدان فيما بينهما"},{"id":"b","text":"يتقاطعان بزاوية حادّة"},{"id":"c","text":"لا يمكن معرفة العلاقة"},{"id":"d","text":"متوازيان فيما بينهما"}]'::jsonb, 'd', 'إذا كان مستقيمان عموديين على مستقيمٍ ثالثٍ نفسِه فهما متوازيان: (د1) ⊥ (د) و(د2) ⊥ (د) ⟹ (د1) ∥ (د2). الخطأ الشائع: ظنُّ أنّهما يصيران متعامدين فيما بينهما.', 6, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
