  ('d6ccc832-6d65-56f0-a618-7d58e1cc1c44', '1c679634-890a-5d92-b9a8-f58f43774564', 'الزاويةُ المنفرجة قيسُها:', '[{"id":"a","text":"يساوي 90°"},{"id":"b","text":"أصغر من 90°"},{"id":"c","text":"أكبر من 90° وأصغر من 180°"},{"id":"d","text":"يساوي 180°"}]'::jsonb, 'c', 'الزاويةُ المنفرجة فتحتُها واسعة: قيسُها أكبرُ من 90° وأصغرُ من 180°.', 1, 'mcq', NULL, NULL)
