  ('7b5889cb-4e97-5386-8e29-4149f1157450', '1c679634-890a-5d92-b9a8-f58f43774564', 'ما نوعُ المثلّث المبيّن في الشكل حسب زواياه؟ <svg viewBox="0 0 100 80"><polygon points="22,70 22,26 72,70" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="22" y="60" width="10" height="10" fill="none" stroke="#1f2937" stroke-width="1.5"/></svg>', '[{"id":"a","text":"حادّ الزوايا"},{"id":"b","text":"قائم الزاوية"},{"id":"c","text":"منفرج الزاوية"},{"id":"d","text":"متساوي الأضلاع"}]'::jsonb, 'b', 'المربّعُ الصغير عند الرأس يدلّ على زاوية قائمة (90°)، فالمثلّثُ قائمُ الزاوية.', 2, 'mcq', NULL, NULL)
