  ('e4816102-6d79-5fe2-b20c-641801f58199', '1c679634-890a-5d92-b9a8-f58f43774564', 'ما هذا الرباعيّ؟ <svg viewBox="0 0 100 100"><rect x="16" y="32" width="68" height="40" fill="none" stroke="currentColor" stroke-width="2.5"/><rect x="16" y="32" width="9" height="9" fill="none" stroke="#1f2937" stroke-width="1.3"/></svg>', '[{"id":"a","text":"مربّع"},{"id":"b","text":"معيّن"},{"id":"c","text":"مستطيل"},{"id":"d","text":"متوازي أضلاع مائل"}]'::jsonb, 'c', 'زواياه قائمة (المربّع الصغير) وطولُه أكبرُ من عرضه (الأضلاع المتقابلة فقط متساوية)، فهو مستطيل.', 3, 'mcq', NULL, NULL)
