  ('c34643b7-4f05-55fa-ac84-2737d10e20d0', '1c679634-890a-5d92-b9a8-f58f43774564', 'أيُّ عبارةٍ صحيحةٌ حول التوازي والتعامد؟', '[{"id":"a","text":"المستقيمان المتوازيان لا يتقاطعان مهما امتدّا"},{"id":"b","text":"المستقيمان المتعامدان لا يتقاطعان أبدًا"},{"id":"c","text":"كلُّ مستقيمين متقاطعين متعامدان"},{"id":"d","text":"المتوازيان يتقاطعان بزاوية قائمة"}]'::jsonb, 'a', 'المتوازيان لا يتقاطعان ويبقى البعدُ بينهما ثابتًا؛ أمّا المتعامدان فيتقاطعان بزاوية قائمة 90°.', 5, 'mcq', NULL, NULL)
