INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('0b5f1bdc-d055-5d8d-94f1-623a2e00fdb4', 'db24cda7-c791-5bbb-8732-fa9cca504722', 'زاويةٌ قيسُها 90° قُسّمت بنصفٍ إلى زاويتين متساويتين. ما نوعُ كلِّ زاوية ناتجة؟', '[{"id":"a","text":"حادّة (45°)"},{"id":"b","text":"قائمة (90°)"},{"id":"c","text":"منفرجة"},{"id":"d","text":"مستقيمة (180°)"}]'::jsonb, 'a', 'نصفُ الزاوية القائمة = 90° ÷ 2 = 45°، وهو أصغرُ من 90° فالزاوية حادّة.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
