INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c161760c-6c52-5a28-8ab1-113a979c0571', 'db24cda7-c791-5bbb-8732-fa9cca504722', 'مثلّثٌ فيه زاويةٌ قائمة وله ضلعان متساويان. أيُّ وصفٍ يطابقه؟', '[{"id":"a","text":"قائم الزاوية ومتساوي الساقين معًا"},{"id":"b","text":"متساوي الأضلاع فقط"},{"id":"c","text":"لا يمكن أن يجتمع الوصفان"},{"id":"d","text":"مختلف الأضلاع"}]'::jsonb, 'a', 'التصنيفُ حسب الزوايا مستقلٌّ عن التصنيف حسب الأضلاع، فيجوز اجتماعُهما: قائمُ الزاوية (زاوية 90°) ومتساوي الساقين (ضلعان متساويان). الخطأ الشائع: ظنُّ أنّ النوعين يتنافيان.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
