  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('1029ee5c-3465-5afe-8206-aa774cf30f94', 'db24cda7-c791-5bbb-8732-fa9cca504722', 'رباعيٌّ أضلاعُه الأربعة متساوية وزواياه الأربعة قائمة. ما أدقُّ اسمٍ له؟', '[{"id":"a","text":"معيّن فقط"},{"id":"b","text":"مستطيل فقط"},{"id":"c","text":"مربّع"},{"id":"d","text":"متوازي أضلاع مختلف الأضلاع"}]'::jsonb, 'c', 'تساوي الأضلاع الأربعة + الزوايا القائمة = مربّع (وهو في الوقت نفسه معيّن ومستطيل). الخطأ الشائع: التوقّفُ عند «معيّن» وإهمالُ شرط الزوايا القائمة الذي يجعله مربّعًا.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('02a71467-a583-5668-973e-1234c12de59a', 'db24cda7-c791-5bbb-8732-fa9cca504722', 'نقطةٌ M تقع على الموسّط العمودي للقطعة [AB]. ماذا نستنتج عن بُعدَيها عن A وعن B؟', '[{"id":"a","text":"MA أكبرُ من MB دائمًا"},{"id":"b","text":"MA أصغرُ من MB دائمًا"},{"id":"c","text":"لا علاقة بينهما"},{"id":"d","text":"MA = MB (متساويان)"}]'::jsonb, 'd', 'كلُّ نقطةٍ على الموسّط العمودي للقطعة [AB] تبعُد بُعدًا متساويًا عن طرفيها: MA = MB. الخطأ الشائع: الخلطُ بين الموسّط (تساوي البعدين) والمستقيم المائل العشوائي.', 4, 'mcq', NULL, NULL)
