INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d1cbfb0b-74e3-5f3c-9504-ae6c8af43883', 'db24cda7-c791-5bbb-8732-fa9cca504722', 'نريد رسمَ زاوية قيسُها 50° بالمنقلة. ما الترتيبُ الصحيح؟ (1) نرسم ضلعًا  (2) نضع مركزَ المنقلة على طرفه ونطابق الصفر مع الضلع  (3) نُعلّم نقطةً عند 50° ونصلُها بالرأس', '[{"id":"a","text":"3 ثمّ 2 ثمّ 1"},{"id":"b","text":"1 ثمّ 2 ثمّ 3"},{"id":"c","text":"2 ثمّ 1 ثمّ 3"},{"id":"d","text":"1 ثمّ 3 ثمّ 2"}]'::jsonb, 'b', 'نرسم الضلعَ أوّلًا (1)، ثمّ نضع المنقلةَ ونطابق الصفر (2)، ثمّ نعلّم 50° ونصل (3). الخطأ الشائع: وضعُ المنقلة قبل رسم الضلع، فلا يكون للزاوية رأسٌ نضع عليه المركز.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
