INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('de5c736d-efd2-5669-a589-fbe2bf145002', 'db24cda7-c791-5bbb-8732-fa9cca504722', 'رباعيٌّ أضلاعُه المتقابلة متوازية ومتساوية، لكنّ زواياه ليست قائمة وأضلاعُه المتجاورة مختلفة الطول. ما اسمُه؟', '[{"id":"a","text":"معيّن"},{"id":"b","text":"مربّع"},{"id":"c","text":"مستطيل"},{"id":"d","text":"متوازي الأضلاع"}]'::jsonb, 'd', 'الأضلاعُ المتقابلة متوازية ومتساوية لكن لا تساويَ للأضلاع الأربعة ولا زوايا قائمة، فهو متوازي أضلاع عامّ. الخطأ الشائع: تسميتُه معيّنًا (يلزمه تساوي الأضلاع الأربعة) أو مستطيلًا (يلزمه زوايا قائمة).', 6, 'mcq', NULL, NULL)
