  ('e58a65cc-be4b-5c68-9a8f-3b8106497635', '7ff6c22e-f0eb-5eb0-b38c-3d328472e4c2', 'ما هو محورُ التناظر؟', '[{"id":"a","text":"المستقيمُ الذي إذا طوينا الورقة عليه انطبق الشكلُ على نظيره"},{"id":"b","text":"النقطةُ الواقعة في منتصف الشكل"},{"id":"c","text":"أطولُ ضلعٍ في الشكل"},{"id":"d","text":"أيُّ مستقيمٍ يمرّ بالشكل"}]'::jsonb, 'a', 'محورُ التناظر هو المستقيمُ الذي إذا طوينا الورقة عليه انطبق نصفا الشكل أحدُهما على الآخر، فيكون كلُّ جزءٍ نظيرًا للآخر.', 1, 'mcq', NULL, NULL)
