  ('1ed5b8a0-a08b-5bbf-8935-07acfedf822e', 'f7921d17-23eb-57e8-8e2c-3f4777ab6d34', 'كم محورَ تناظرٍ للمستطيل (غير المربّع)؟', '[{"id":"a","text":"محورٌ واحد"},{"id":"b","text":"لا محورَ له"},{"id":"c","text":"محوران"},{"id":"d","text":"4 محاور"}]'::jsonb, 'c', 'للمستطيل محورا تناظر: المستقيمان المارّان بمنتصفَي الضلعين المتقابلين. قُطراه ليسا محورَي تناظر.', 4, 'mcq', NULL, NULL)
