INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('de6a2367-3a0e-5e2b-af47-ff3bdc12a585', '24784e63-dcdf-5565-81ef-c825778d0ed8', 'لإيجاد نظير مثلّثٍ بالنسبة إلى مستقيم، نوجد:', '[{"id":"a","text":"منتصفَ كلِّ ضلع"},{"id":"b","text":"مركزَ المثلّث"},{"id":"c","text":"نظيرَ كلِّ رأسٍ من رؤوسه ثمّ نصل بينها بالترتيب نفسه"},{"id":"d","text":"نظيرَ رأسٍ واحدٍ فقط ونكتفي به"}]'::jsonb, 'c', 'نظيرُ شكلٍ هو الشكلُ المكوّنُ من نظائر رؤوسه: نوجد نظيرَ كلِّ رأسٍ ثمّ نصلها بالترتيب نفسه فنحصل على نظير المثلّث المطابق له.', 1, 'mcq', NULL, NULL)
