INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('5a3cea6e-1941-517c-9a4f-c0c0d993a055', '24784e63-dcdf-5565-81ef-c825778d0ed8', 'كم محورَ تناظرٍ لهذا الشكل (معيّن)؟ <svg viewBox="0 0 100 100"><polygon points="50,16 74,50 50,84 26,50" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="50" y1="15" x2="50" y2="85" stroke="#ef4444" stroke-width="1.3" stroke-dasharray="4 3"/><line x1="15" y1="50" x2="85" y2="50" stroke="#ef4444" stroke-width="1.3" stroke-dasharray="4 3"/></svg>', '[{"id":"a","text":"محوران (قُطراه)"},{"id":"b","text":"4 محاور"},{"id":"c","text":"محورٌ واحد"},{"id":"d","text":"لا محورَ له"}]'::jsonb, 'a', 'للمعيّن محورا تناظرٍ هما قُطراه (المتقطّعان في الشكل). الخطأ الشائع: ظنُّ أنّ له 4 محاورٍ كالمربّع؛ لكنّ المستقيمين المارّين بمنتصفَي ضلعيه ليسا محورَي تناظرٍ لأنّ زواياه ليست قائمة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
