  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('d2a35f4c-ce37-558d-82de-a0893c97712b', '24784e63-dcdf-5565-81ef-c825778d0ed8', 'نقطةٌ B تبعد 4 وحداتٍ يمينَ المحور. أين يقع نظيرُها B′؟', '[{"id":"a","text":"على بُعد وحدتين يسارَ المحور"},{"id":"b","text":"على بُعد 4 وحداتٍ يسارَ المحور، على نفس العمود"},{"id":"c","text":"على بُعد 4 وحداتٍ يمينَ المحور (نفس الجهة)"},{"id":"d","text":"على بُعد 8 وحداتٍ يسارَ المحور"}]'::jsonb, 'b', 'النظيرُ يقع على الجهة المقابلة (اليسار) على نفس العمود وبنفس البُعد: 4 وحدات. الخطأ الشائع: ترك النقطة على الجهة نفسها (يمين)، أو مضاعفة البُعد إلى 8 وحدات؛ كلاهما يخالف تساوي البُعد عن المحور.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
