  ('b7e02cd4-a7cb-5929-a4f7-cc1f8050e755', '24784e63-dcdf-5565-81ef-c825778d0ed8', 'نظيرُ مستقيمٍ بالنسبة إلى محورٍ هو:', '[{"id":"a","text":"مستقيمٌ أيضًا"},{"id":"b","text":"منحنٍ"},{"id":"c","text":"نقطةٌ واحدة"},{"id":"d","text":"خطٌّ منكسر"}]'::jsonb, 'a', 'التناظرُ المحوري يحفظ الاستقامة، فصورةُ (نظيرُ) كلِّ مستقيمٍ مستقيمٌ مثلُه. الخطأ الشائع: ظنُّ أنّ الانعكاس «يقوّس» الخطّ؛ بل يحفظ شكلَه ويغيّر اتّجاهه فقط.', 5, 'mcq', NULL, NULL)
