  ('6855cd8e-00c3-51c0-b98d-8cdb344dcc2d', '24784e63-dcdf-5565-81ef-c825778d0ed8', 'للحرف H محوران للتناظر، وللحرف A محورٌ واحد. كم محورًا لهما معًا؟', '[{"id":"a","text":"4 محاور"},{"id":"b","text":"محورٌ واحد"},{"id":"c","text":"3 محاور"},{"id":"d","text":"محوران"}]'::jsonb, 'c', 'للحرف H محوران (عموديٌّ وأفقيّ) وللحرف A محورٌ واحد (عموديّ)، والمجموع 2 + 1 = 3 محاور.', 6, 'mcq', NULL, NULL)
