INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cd61f8d3-e7af-5aaf-87ae-f8298e8be3f9', '4f453598-9e51-5e3a-b66f-431e2d8215e9', 'أيُّ جملةٍ صحيحةٌ عن محاور تناظر الأشكال؟', '[{"id":"a","text":"للمربّع 4 محاور وللمستطيل والمعيّن محوران لكلٍّ منهما"},{"id":"b","text":"للمربّع والمستطيل العددُ نفسه من المحاور"},{"id":"c","text":"للدائرة 4 محاور فقط"},{"id":"d","text":"للمثلّث مختلف الأضلاع 3 محاور"}]'::jsonb, 'a', 'للمربّع 4 محاور، وللمستطيل 2، وللمعيّن 2، فالجملة الصحيحة هي أنّ للمربّع 4 محاور وللمستطيل والمعيّن محوران لكلٍّ منهما. أمّا الدائرة فمحاورُها لا نهائية، والمثلّثُ مختلفُ الأضلاع لا محورَ له.', 6, 'mcq', NULL, NULL)
