  ('359e9446-ba97-5fe3-9a41-ffd9ca28f62f', '242785f0-beea-54f0-9857-d477e24852c0', 'math-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: ألغاز المرآة', 4, 300, 60, 'challenge', 'admin', 4)
