INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('cb9d2b0f-78a6-575e-9813-496c0ffc6d9e', '359e9446-ba97-5fe3-9a41-ffd9ca28f62f', 'نقطةٌ M تقع على بُعد 3 مربّعاتٍ يمينَ المحور وعلى بُعد مربّعين فوق نقطةٍ على المحور. أين يقع نظيرُها M′؟', '[{"id":"a","text":"3 مربّعاتٍ يسارَ المحور، على نفس الارتفاع"},{"id":"b","text":"3 مربّعاتٍ يسارَ المحور، مربّعين أسفل"},{"id":"c","text":"3 مربّعاتٍ يمينَ المحور، مربّعين أسفل"},{"id":"d","text":"مربّعين يسارَ المحور، على نفس الارتفاع"}]'::jsonb, 'a', 'في التناظر بالنسبة لمحورٍ عموديّ، تتغيّر الجهة (يمين ↔ يسار) ويبقى البُعد الأفقي 3 والارتفاع نفسه. الخطأ الشائع: تغيير الارتفاع أيضًا (مربّعين أسفل)، أو إنقاص البُعد إلى مربّعين؛ المحورُ العمودي لا يغيّر الارتفاع.', 1, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('2d0ba5d9-0af3-5561-8d7e-9fff35df69e8', '359e9446-ba97-5fe3-9a41-ffd9ca28f62f', 'نظيرُ هذا المثلّث بالنسبة إلى المحور المتقطّع رُسم على اليمين. ما العلاقةُ بين المثلّث ونظيره؟ <svg viewBox="0 0 110 100"><line x1="10" y1="25" x2="100" y2="25" stroke="#cbd5e1" stroke-width="0.5"/><line x1="10" y1="45" x2="100" y2="45" stroke="#cbd5e1" stroke-width="0.5"/><line x1="10" y1="65" x2="100" y2="65" stroke="#cbd5e1" stroke-width="0.5"/><line x1="10" y1="85" x2="100" y2="85" stroke="#cbd5e1" stroke-width="0.5"/><line x1="55" y1="12" x2="55" y2="90" stroke="currentColor" stroke-width="1.6" stroke-dasharray="5 3"/><polygon points="25,85 25,45 45,65" fill="none" stroke="currentColor" stroke-width="2.5"/><polygon points="85,85 85,45 65,65" fill="none" stroke="currentColor" stroke-width="2.5"/><text x="57" y="19" font-size="9" fill="currentColor">(d)</text></svg>', '[{"id":"a","text":"النظيرُ أصغرُ من الأصل"},{"id":"b","text":"النظيرُ منقولٌ دون انعكاسٍ (بنفس الاتّجاه)"},{"id":"c","text":"متطابقان في الحجم لكنّهما معكوسان (يمين ↔ يسار)"},{"id":"d","text":"النظيرُ أكبرُ من الأصل"}]'::jsonb, 'c', 'التناظرُ يحفظ الأطوال والزوايا، فالمثلّثان متطابقان في الحجم؛ لكنّ الرأس المدبّب يتّجه يمينًا في الأصل ويسارًا في النظير. الخطأ الشائع: ظنُّ النظير منقولًا بنفس الاتّجاه دون انعكاس؛ لو كان كذلك لاتّجه الرأسان نفسَ الجهة.', 2, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('80cd5601-d6ef-56a4-9cab-ada539919db0', '359e9446-ba97-5fe3-9a41-ffd9ca28f62f', 'للمربّع 4 محاور تناظر وللمعيّن محوران. كم محورًا لهما معًا، وكم محورًا أكثرُ للمربّع؟', '[{"id":"a","text":"محوران معًا، والمربّعُ يزيد بمحورٍ واحد"},{"id":"b","text":"6 محاورٍ معًا، والمربّعُ يزيد بمحورين"},{"id":"c","text":"6 محاورٍ معًا، والمربّعُ يزيد بـ 4 محاور"},{"id":"d","text":"8 محاورٍ معًا، والمربّعُ يزيد بمحورين"}]'::jsonb, 'b', 'المجموع 4 + 2 = 6 محاور، والفرق 4 − 2 = 2، فالمربّعُ يزيد بمحورين. سببُ الفرق أنّ زوايا المربّع قائمة، فيضيف محورَي منتصفَي الأضلاع إلى قُطريه؛ أمّا المعيّن فقُطراه فقط.', 3, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('c77ae57d-d9a0-5ec3-b13b-b02c2afad8a8', '359e9446-ba97-5fe3-9a41-ffd9ca28f62f', 'إذا كان نظيرُ النقطة A هو A نفسها بالنسبة إلى محورٍ ما، فماذا نستنتج عن موضع A؟', '[{"id":"a","text":"النقطة A تبعد وحدةً عن المحور"},{"id":"b","text":"النقطة A خارج الورقة"},{"id":"c","text":"لا يمكن أن يحدث ذلك أبدًا"},{"id":"d","text":"النقطة A تقع على المحور نفسه"}]'::jsonb, 'd', 'النقطةُ تنطبق على نظيرها فقط عندما يكون بُعدُها عن المحور صفرًا، أي تقع على المحور. كلُّ نقاط المحور ثابتةٌ بالتناظر (نظيرُها هي نفسها).', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('079672aa-2bbb-5ea3-94c3-024a2e924dfb', '359e9446-ba97-5fe3-9a41-ffd9ca28f62f', 'قطعةٌ [A B] طولُها 6 سم، ومنتصفُها I. ما طولُ نظيرتها [A′ B′]، وأين يقع نظيرُ المنتصف I′؟', '[{"id":"a","text":"6 سم، وI′ منتصفُ [A′ B′]"},{"id":"b","text":"3 سم، وI′ منتصفُ [A′ B′]"},{"id":"c","text":"6 سم، وI′ أحدُ طرفَي [A′ B′]"},{"id":"d","text":"12 سم، وI′ خارجَ القطعة"}]'::jsonb, 'a', 'التناظرُ يحفظ الأطوال، فطولُ [A′ B′] = 6 سم، ويحفظ النِّسَب، فنظيرُ المنتصف يبقى منتصفًا: I′ منتصفُ [A′ B′]. الخطأ الشائع: تنصيفُ الطول إلى 3 سم ظنًّا أنّ الانعكاس يصغّر القطعة.', 5, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order,
