INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('971d5c34-fa4a-5d8b-89b8-019102ffaac3', 'c44b76b7-e6e0-5a24-b931-6de717b9371e', 'لإنشاء نظير نقطةٍ بالأدوات (بالمسطرة والكوس)، نرسم من النقطة خطًّا:', '[{"id":"a","text":"موازيًا للمحور، ثمّ ننقل البُعد"},{"id":"b","text":"عموديًّا على المحور، ثمّ ننقل البُعد نفسه على الجهة الأخرى"},{"id":"c","text":"يمرّ بأيِّ نقطةٍ من المحور"},{"id":"d","text":"بزاوية 45° مع المحور"}]'::jsonb, 'b', 'نرسم من النقطة عمودًا على المحور بالكوس، نقيس بُعدَها عن المحور، ثمّ ننقل البُعد نفسه على الجهة المقابلة على نفس العمود، فنحصل على النظير.', 1, 'mcq', NULL, NULL)
