  ('1ab6edec-d6aa-5c75-8bc6-777284f4bce7', 'c44b76b7-e6e0-5a24-b931-6de717b9371e', 'نظيرُ المثلّث متساوي الأضلاع بالنسبة إلى محورٍ هو مثلّثٌ:', '[{"id":"a","text":"متساوي الأضلاع أيضًا (مطابق له)"},{"id":"b","text":"متساوي الساقين فقط"},{"id":"c","text":"مختلفُ الأضلاع"},{"id":"d","text":"قائمُ الزاوية"}]'::jsonb, 'a', 'التناظرُ يحفظ الأطوال، فأضلاعُ النظير الثلاثة تبقى متساوية مثلَ الأصل: النظيرُ مثلّثٌ متساوي الأضلاع مطابقٌ له.', 2, 'mcq', NULL, NULL)
