INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('02a846b7-f852-5631-b5a1-1de91a26bcc3', 'c44b76b7-e6e0-5a24-b931-6de717b9371e', 'كم محورَ تناظرٍ لهذا المربّع؟ <svg viewBox="0 0 100 100"><rect x="28" y="28" width="44" height="44" fill="none" stroke="currentColor" stroke-width="2.5"/><line x1="50" y1="20" x2="50" y2="80" stroke="#ef4444" stroke-width="1.3" stroke-dasharray="4 3"/><line x1="20" y1="50" x2="80" y2="50" stroke="#ef4444" stroke-width="1.3" stroke-dasharray="4 3"/><line x1="28" y1="28" x2="72" y2="72" stroke="#ef4444" stroke-width="1.3" stroke-dasharray="4 3"/><line x1="72" y1="28" x2="28" y2="72" stroke="#ef4444" stroke-width="1.3" stroke-dasharray="4 3"/></svg>', '[{"id":"a","text":"محوران"},{"id":"b","text":"3 محاور"},{"id":"c","text":"4 محاور"},{"id":"d","text":"عددٌ لا نهائيّ"}]'::jsonb, 'c', 'للمربّع 4 محاور تناظرٍ ظاهرةٌ في الشكل: محورا منتصفَي الأضلاع (عموديٌّ وأفقيّ) والقُطران. الخطأ الشائع: عدُّ محورين فقط كالمستطيل ونسيانُ القُطرين.', 3, 'mcq', NULL, NULL)
