INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('aa6b9752-0fa9-5145-9192-6f67886fadea', 'c44b76b7-e6e0-5a24-b931-6de717b9371e', 'نقطتان A و A′ متناظرتان بالنسبة إلى مستقيم (d). إذا كان طولُ [A A′] يساوي 8 سم، فكم تبعد A عن المحور (d)؟', '[{"id":"a","text":"4 سم"},{"id":"b","text":"8 سم"},{"id":"c","text":"16 سم"},{"id":"d","text":"2 سم"}]'::jsonb, 'a', 'المحورُ يمرّ بمنتصف [A A′]، فبُعدُ A عنه نصفُ الطول: 8 ÷ 2 = 4 سم. الخطأ الشائع: أخذُ الطول كلِّه (8 سم)، لكنّ A لا تبعد إلّا نصفَ المسافة بينها وبين نظيرها.', 4, 'mcq', NULL, NULL)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
