  display_order = EXCLUDED.display_order,
  question_type = EXCLUDED.question_type,
  answer_key = EXCLUDED.answer_key,
  distractor_tags = EXCLUDED.distractor_tags;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order, question_type, answer_key, distractor_tags) VALUES
  ('ce67b0fb-a8e4-5679-b939-bfdca65363e6', 'c44b76b7-e6e0-5a24-b931-6de717b9371e', 'أيُّ هذه الجمل **خاطئة**؟', '[{"id":"a","text":"نظيرُ نقطةٍ على المحور هو النقطةُ نفسها"},{"id":"b","text":"للمعيّن محورا تناظر"},{"id":"c","text":"نظيرُ مستقيمٍ مستقيم"},{"id":"d","text":"التناظرُ المحوري يضاعفُ أطوالَ الأضلاع"}]'::jsonb, 'd', 'الجملةُ الخاطئة هي «التناظرُ يضاعفُ الأطوال»: بل هو يحفظ الأطوال ولا يغيّرها. أمّا الجمل الأخرى فصحيحة: نقاطُ المحور ثابتة، وللمعيّن محوران، ونظيرُ المستقيم مستقيم.', 5, 'mcq', NULL, NULL)
